-- Step1: Creates a master key for encryption
CREATE MASTER KEY ENCRYPTION BY PASSWORD = 'AzureInceptez@_123!';

-- Step2: Create a credential using the Workspace Managed Identity
CREATE DATABASE SCOPED CREDENTIAL wsidentity
WITH IDENTITY = 'Managed Identity';

--Step3: Create an External Data Source
DROP EXTERNAL DATA SOURCE bankdata_src
CREATE EXTERNAL DATA SOURCE bankdata_src
WITH
(
    LOCATION = 'abfss://bankdata@inceptezadlsbankdata.dfs.core.windows.net/',
    CREDENTIAL = wsidentity
);

--Step4: Create an External file format
CREATE EXTERNAL FILE FORMAT bankdata_fileformat
WITH
(
    FORMAT_TYPE = DELIMITEDTEXT,
    FORMAT_OPTIONS (
        FIELD_TERMINATOR = ',',
        FIRST_ROW = 2
    )
);


DROP EXTERNAL TABLE bank_schema.bank_txns_ext;
CREATE EXTERNAL TABLE bank_schema.bank_txns_ext
(
    txnid varchar(10),
    txndate date,
    custid varchar(20),
    amt float,
    branch varchar(50),
    region varchar(50),
    payment_type varchar(20)
)
WITH
(
    LOCATION = 'bank_txns.csv',
    DATA_SOURCE = bankdata_src,
    FILE_FORMAT = bankdata_fileformat
);

select * from bank_schema.bank_txns_ext;


--insert int.. copy from external table to dedicated sql table
insert into bank_schema.bank_txns select txnid,txndate,custid,amt,branch,region from bank_schema.bank_txns_ext;

--CTAS
CREATE TABLE bank_schema.bank_txns1
WITH
(
    DISTRIBUTION = ROUND_ROBIN
)
AS
select txnid,txndate,custid,amt,branch,region from bank_schema.bank_txns_ext;

select * from bank_schema.bank_txns1;
